    card.appendChild(titleNode);
    if(item&&(item.author||item.date)){ const byline=make('div','byline'); if(item.author) byline.appendChild(make('span','',String(item.author))); if(item.date) byline.appendChild(make('span','',String(item.date))); card.appendChild(byline); }
    if(item&&item.snippet) card.appendChild(make('blockquote','snippet',String(item.snippet))); grid.appendChild(card);
  });
